WITH tx AS (SELECT business_id, transaction_month AS month, SUM(CASE WHEN amount>0 THEN amount ELSE 0 END) cash_inflow, SUM(CASE WHEN amount<0 THEN -amount ELSE 0 END) cash_outflow, SUM(amount) net_cash_flow, COUNT(*) transaction_count FROM bank_transactions GROUP BY 1,2), repay AS (SELECT business_id, payment_month AS month, SUM(scheduled_amount) scheduled_debt_service, MAX(days_past_due) max_dpd FROM repayments GROUP BY 1,2), inv AS (SELECT business_id, invoice_month AS month, AVG(days_to_pay) avg_days_to_pay, AVG(is_late) late_invoice_rate FROM invoices GROUP BY 1,2), pay AS (SELECT business_id, payroll_month AS month, SUM(payroll_amount) payroll_amount FROM payroll GROUP BY 1,2) SELECT c.business_id, c.industry, c.region, c.revenue_band, t.*, COALESCE(r.scheduled_debt_service,0) scheduled_debt_service, COALESCE(r.max_dpd,0) max_dpd, i.avg_days_to_pay, i.late_invoice_rate, COALESCE(p.payroll_amount,0) payroll_amount, COALESCE(r.scheduled_debt_service,0)/NULLIF(t.cash_inflow,0) repayment_burden_ratio, COALESCE(p.payroll_amount,0)/NULLIF(t.cash_inflow,0) payroll_burden_ratio FROM tx t LEFT JOIN business_customers c USING(business_id) LEFT JOIN repay r USING(business_id, month) LEFT JOIN inv i USING(business_id, month) LEFT JOIN pay p USING(business_id, month) ORDER BY business_id, month;